'use strict';

const assert = require('../testUtils/assert');
const removeDefaultValuesAS3 = require('../../src/postConverter/removeDefaultValuesAS3');
const objectUtil = require('../../src/util/object');

describe('Extended objects (removeDefaultValuesAS3.js)', () => {
    it('should remove default values from AS3 objects', () => {
        const extended = {
            class: 'ADC',
            schemaVersion: '3.26.0',
            AS3_Tenant: {
                class: 'Tenant',
                AS3_Application: {
                    class: 'Application',
                    template: 'generic',
                    httpProf: {
                        trustXFF: false,
                        knownMethods: [
                            'CONNECT', 'DELETE', 'GET', 'HEAD',
                            'LOCK', 'OPTIONS', 'POST', 'PROPFIND',
                            'PUT', 'TRACE', 'UNLOCK'
                        ],
                        maxRequests: 0,
                        pipelineAction: 'allow',
                        unknownMethodAction: 'allow',
                        hstsIncludeSubdomains: true,
                        hstsPeriod: 7862400,
                        hstsInsert: false,
                        hstsPreload: false,
                        xForwardedFor: true,
                        multiplexTransformations: true,
                        proxyType: 'reverse',
                        rewriteRedirects: 'none',
                        serverHeaderValue: 'BigIP',
                        viaRequest: 'remove',
                        viaResponse: 'remove',
                        class: 'HTTP_Profile'
                    }
                }
            }
        };
        const output = removeDefaultValuesAS3(extended, false);
        const expected = {
            class: 'ADC',
            schemaVersion: '3.26.0',
            AS3_Tenant: {
                class: 'Tenant',
                AS3_Application: {
                    class: 'Application',
                    template: 'generic',
                    httpProf: {
                        class: 'HTTP_Profile'
                    }
                }
            }
        };

        assert.deepStrictEqual(output, expected);
    });

    it('should not fail if inspected object has ref in else block of AS3 schema', () => {
        const extended = {
            class: 'ADC',
            schemaVersion: '3.26.0',
            id: 'urn:uuid:a35f7126-83ca-4100-9772-a7bc4c532da0',
            label: 'F5 BIG-IP Converted Declaration',
            remark: 'Generated by Automation Config Converter',
            AS3_Tenant: {
                class: 'Tenant',
                AS3_Application: {
                    class: 'Application',

                    template: 'generic',
                    vs1: {
                        translateServerAddress: false,
                        translateServerPort: false,
                        class: 'Service_Forwarding',
                        profileL4: {
                            bigip: '/Common/apm-forwarding-fastL4'
                        },
                        forwardingType: 'ip',
                        virtualAddresses: [
                            [
                                '0.0.0.0/0',
                                '10.10.192.0/24'
                            ]
                        ],
                        virtualPort: 0,
                        persistenceMethods: [],
                        layer4: 'any',
                        snat: 'none'
                    }
                }
            }
        };
        const output = removeDefaultValuesAS3(extended, false);
        const expected = {
            class: 'ADC',
            schemaVersion: '3.26.0',
            id: 'urn:uuid:a35f7126-83ca-4100-9772-a7bc4c532da0',
            label: 'F5 BIG-IP Converted Declaration',
            remark: 'Generated by Automation Config Converter',
            AS3_Tenant: {
                class: 'Tenant',
                AS3_Application: {
                    class: 'Application',
                    template: 'generic',
                    vs1: {
                        translateServerAddress: false,
                        translateServerPort: false,
                        class: 'Service_Forwarding',
                        profileL4: {
                            bigip: '/Common/apm-forwarding-fastL4'
                        },
                        forwardingType: 'ip',
                        virtualAddresses: [
                            [
                                '0.0.0.0/0',
                                '10.10.192.0/24'
                            ]
                        ],
                        virtualPort: 0,
                        persistenceMethods: [],
                        snat: 'none'
                    }
                }
            }
        };
        assert.deepStrictEqual(output, expected);
    });

    it('should not fail on UNCERTAIN_CERT', () => {
        const extended = {
            class: 'ADC',
            schemaVersion: '3.26.0',
            id: 'urn:uuid:a35f7126-83ca-4100-9772-a7bc4c532da0',
            label: 'F5 BIG-IP Converted Declaration',
            remark: 'Generated by Automation Config Converter',
            AS3_Tenant: {
                class: 'Tenant',
                AS3_Application: {
                    class: 'Application',
                    edge_case: {
                        certificates: [
                            {
                                certificate: '/Common/Shared/default_certificate'
                            }
                        ],
                        class: 'UNCERTAIN_CERT',
                        tls1_0Enabled: false,
                        tls1_1Enabled: false,
                        tls1_2Enabled: true,
                        tls1_3Enabled: true,
                        singleUseDhEnabled: false,
                        insertEmptyFragmentsEnabled: false
                    }
                }
            }
        };

        const output = removeDefaultValuesAS3(extended, false);
        const expected = {
            class: 'ADC',
            schemaVersion: '3.26.0',
            id: 'urn:uuid:a35f7126-83ca-4100-9772-a7bc4c532da0',
            label: 'F5 BIG-IP Converted Declaration',
            remark: 'Generated by Automation Config Converter',
            AS3_Tenant: {
                class: 'Tenant',
                AS3_Application: {
                    class: 'Application',
                    edge_case: {
                        certificates: [
                            {
                                certificate: '/Common/Shared/default_certificate'
                            }
                        ],
                        class: 'UNCERTAIN_CERT',
                        tls1_0Enabled: false,
                        tls1_1Enabled: false,
                        tls1_2Enabled: true,
                        tls1_3Enabled: true,
                        singleUseDhEnabled: false,
                        insertEmptyFragmentsEnabled: false
                    }
                }
            }
        };
        assert.deepStrictEqual(output, expected);
    });
});

describe('Test removeDefaultProfiles from removeDefaultValuesAS3.js', () => {
    it('delete one default profile of a service', () => {
        const input = {
            class: 'ADC',
            schemaVersion: '3.39.0',
            id: 'urn:uuid:1858afbd-bb2e-4984-89e3-18f3aacfe498',
            label: 'F5 BIG-IP Converted Declaration',
            remark: 'Generated by Automation Config Converter',
            Common: {
                class: 'Tenant',
                Shared: {
                    class: 'Application',
                    template: 'shared',
                    an_app: {
                        remark: 'Shared',
                        layer4: 'udp',
                        translateServerAddress: false,
                        translateServerPort: false,
                        class: 'Service_UDP',
                        profileUDP: {
                            bigip: '/Common/udp'
                        },
                        virtualAddresses: [
                            '10.1.1.7'
                        ],
                        virtualPort: 1234,
                        snat: 'auto'
                    }
                }
            }
        };

        const expected = JSON.parse(JSON.stringify(input));
        // delete the profile
        delete expected.Common.Shared.an_app.profileUDP;
        const output = removeDefaultValuesAS3(input, false);
        assert.deepStrictEqual(output, expected);
    });

    it('delete two default profiles of a service', () => {
        const input = {
            class: 'ADC',
            schemaVersion: '3.39.0',
            id: 'urn:uuid:1858afbd-bb2e-4984-89e3-18f3aacfe498',
            label: 'F5 BIG-IP Converted Declaration',
            remark: 'Generated by Automation Config Converter',
            Common: {
                class: 'Tenant',
                Shared: {
                    class: 'Application',
                    template: 'shared',
                    an_app: {
                        remark: 'Shared',
                        layer4: 'tcp',
                        translateServerAddress: false,
                        translateServerPort: false,
                        class: 'Service_HTTP',
                        profileTCP: {
                            bigip: '/Common/f5-tcp-progressive'
                        },
                        profileHTTP: {
                            bigip: '/Common/http'
                        },
                        virtualAddresses: [
                            '10.1.1.7'
                        ],
                        virtualPort: 1234,
                        snat: 'auto'
                    }
                }
            }
        };

        const expected = JSON.parse(JSON.stringify(input));
        // delete the profiles
        delete expected.Common.Shared.an_app.profileTCP;
        delete expected.Common.Shared.an_app.profileHTTP;
        const output = removeDefaultValuesAS3(input, false);
        assert.deepStrictEqual(output, expected);
    });

    it('keep a non default profile of a service', () => {
        const input = {
            class: 'ADC',
            schemaVersion: '3.39.0',
            id: 'urn:uuid:1858afbd-bb2e-4984-89e3-18f3aacfe498',
            label: 'F5 BIG-IP Converted Declaration',
            remark: 'Generated by Automation Config Converter',
            Common: {
                class: 'Tenant',
                Shared: {
                    class: 'Application',
                    template: 'shared',
                    an_app: {
                        remark: 'Shared',
                        translateServerAddress: false,
                        translateServerPort: false,
                        class: 'Service_Forwarding',
                        profileL4: {
                            bigip: '/Common/nonDefaultProfile'
                        },
                        forwardingType: 'ip',
                        virtualAddresses: [
                            '10.1.1.7'
                        ],
                        virtualPort: 1234,
                        snat: 'auto'
                    }
                }
            }
        };

        // nothing should change in the case of a non-default profile
        const output = removeDefaultValuesAS3(input, false);
        assert.deepStrictEqual(output, input);
    });

    it('delete default profiles for two services', () => {
        const input = {
            class: 'ADC',
            schemaVersion: '3.39.0',
            id: 'urn:uuid:1858afbd-bb2e-4984-89e3-18f3aacfe498',
            label: 'F5 BIG-IP Converted Declaration',
            remark: 'Generated by Automation Config Converter',
            Common: {
                class: 'Tenant',
                Shared: {
                    class: 'Application',
                    template: 'shared',
                    an_app: {
                        remark: 'Shared',
                        layer4: 'tcp',
                        translateServerAddress: false,
                        translateServerPort: false,
                        class: 'Service_L4',
                        profileL4: {
                            bigip: '/Common/fastL4'
                        },
                        virtualAddresses: [
                            '10.1.1.7'
                        ],
                        virtualPort: 1234,
                        snat: 'auto'
                    },
                    another_app: {
                        remark: 'Shared',
                        layer4: 'tcp',
                        translateServerAddress: false,
                        translateServerPort: false,
                        class: 'Service_TCP',
                        profileTCP: {
                            bigip: '/Common/f5-tcp-progressive'
                        },
                        virtualAddresses: [
                            '10.1.1.7'
                        ],
                        virtualPort: 1234,
                        snat: 'auto'
                    }
                }
            }
        };

        const expected = JSON.parse(JSON.stringify(input));
        // delete the profiles
        delete expected.Common.Shared.an_app.profileL4;
        delete expected.Common.Shared.another_app.profileTCP;
        const output = removeDefaultValuesAS3(input, false);
        assert.deepStrictEqual(output, expected);
    });
});

describe('Test removeDefaultValuesAS3 for Next and Core', () => {
    it('Next and Core have different defaults for tls1_3Enabled', () => {
        const inputCore = {
            class: 'ADC',
            remark: 'Generated by Automation Config Converter',
            Common: {
                class: 'Tenant',
                Shared: {
                    class: 'Application',
                    template: 'shared',
                    certificate_default: {
                        class: 'Certificate',
                        certificate: {
                            bigip: '/Common/default.crt'
                        },
                        privateKey: {
                            bigip: '/Common/default.key'
                        }
                    },
                    'clientssl-tlsv1.1': {
                        certificates: [
                            {
                                certificate: 'certificate_default'
                            }
                        ],
                        class: 'TLS_Server',
                        tls1_0Enabled: true,
                        tls1_1Enabled: true,
                        tls1_2Enabled: false,
                        tls1_3Enabled: false,
                        singleUseDhEnabled: false,
                        insertEmptyFragmentsEnabled: false
                    },
                    'clientssl-tlsv1.2': {
                        certificates: [
                            {
                                certificate: 'certificate_default'
                            }
                        ],
                        class: 'TLS_Server',
                        tls1_0Enabled: true,
                        tls1_1Enabled: false,
                        tls1_2Enabled: true,
                        tls1_3Enabled: false,
                        singleUseDhEnabled: false,
                        insertEmptyFragmentsEnabled: false
                    },
                    'clientssl-tlsv1.3': {
                        certificates: [
                            {
                                certificate: 'certificate_default'
                            }
                        ],
                        cipherGroup: {
                            bigip: '/Common/f5-default'
                        },
                        class: 'TLS_Server',
                        tls1_0Enabled: true,
                        tls1_1Enabled: false,
                        tls1_2Enabled: false,
                        tls1_3Enabled: true,
                        singleUseDhEnabled: false,
                        insertEmptyFragmentsEnabled: false
                    }
                }
            }
        };

        const tlsList = ['clientssl-tlsv1.1', 'clientssl-tlsv1.2', 'clientssl-tlsv1.3'];

        const expectedCore = objectUtil.cloneDeep(inputCore);
        // delete properties with values matching defaults for Core
        tlsList.forEach((tls) => {
            const obj = expectedCore.Common.Shared[tls];
            const propListDefaultTrue = ['tls1_0Enabled', 'tls1_1Enabled', 'tls1_2Enabled'];
            propListDefaultTrue.forEach((prop) => {
                if (obj[prop] !== undefined && obj[prop] === true) {
                    delete obj[prop];
                }
            });

            // unlike other tls's in Core, 'tls1_3Enabled' has default 'false'
            const propListDefaultFalse = ['tls1_3Enabled', 'singleUseDhEnabled', 'insertEmptyFragmentsEnabled'];
            propListDefaultFalse.forEach((prop) => {
                if (obj[prop] !== undefined && obj[prop] === false) {
                    delete obj[prop];
                }
            });
        });

        // Compare for Core, isNext is 'false'
        const outputCore = removeDefaultValuesAS3(inputCore, false);
        assert.deepStrictEqual(outputCore, expectedCore);

        // when isNext is 'undefined', it should behave as Core
        const outputUndefined = removeDefaultValuesAS3(inputCore, undefined);
        assert.deepStrictEqual(outputUndefined, expectedCore);

        // some properties are not supported in Next they supposed to be dropped by validate()
        const inputNext = objectUtil.cloneDeep(inputCore);
        tlsList.forEach((tls) => {
            const obj = inputNext.Common.Shared[tls];
            const obsoletePropList = ['tls1_0Enabled', 'singleUseDhEnabled',
                'insertEmptyFragmentsEnabled', 'cipherGroup'];
            obsoletePropList.forEach((prop) => {
                delete obj[prop];
            });
        });

        const expectedNext = objectUtil.cloneDeep(inputNext);
        // delete properties with values matching defaults for Next
        tlsList.forEach((tls) => {
            const obj = expectedNext.Common.Shared[tls];
            // same as other tls's in Next, 'tls1_3Enabled' has default 'true' in Next
            const propListDefaultTrue = ['tls1_0Enabled', 'tls1_1Enabled', 'tls1_2Enabled', 'tls1_3Enabled'];
            propListDefaultTrue.forEach((prop) => {
                if (obj[prop] !== undefined && obj[prop] === true) {
                    delete obj[prop];
                }
            });
        });

        // Compare for Next, isNext is 'true'
        const outputNext = removeDefaultValuesAS3(inputNext, true);
        assert.deepStrictEqual(outputNext, expectedNext);
    });
});
